#include<bits/stdc++.h>
using namespace std;
vector<pair<long long,long long>> mp[250010],mp1[250010];
long long f[250010],rnk[250010],a[250010],b[250010],min1[250010][21],dfn[250010],flag[250010],dfncnt,fa[250010][21],dis[250010],d[250010],lg[250010];
void dfs(long long x,long long f=0)
{
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    fa[x][0]=f;
    d[x]=d[f]+1;
    for(long long i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=f)
        {
            dis[v]=dis[x]+val;
            dfs(v,x);
        }
    }
}
long long lca(long long x,long long y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(long long i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
long long dist(long long x,long long y)
{
    return dis[x]+dis[y]-dis[lca(x,y)]*2;
}
bool vis[250010];
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(long long i=1;i<n;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u].push_back({v,w});
        mp[v].push_back({u,w});
    }
    dfs(1);
    set<int> s;
    long long ans=0;
    for(int i=1;i<=m;i++)
    {
        int x;
        scanf("%d",&x);
        x=dfn[x];
        if(!vis[rnk[x]])
        {
            s.insert(x);
        }
        auto it=s.lower_bound(x);
        int y,z;
        if(it==s.begin())
        {
            y=(*s.rbegin());
        }
        else
        {
            y=(*(--it));
        }
        it=s.upper_bound(x);
        if(it==s.end())
        {
            z=(*s.begin());
        }
        else
        {
            z=(*it);
        }
        y=rnk[y];
        z=rnk[z];
        if(vis[rnk[x]])
        {
            s.erase(x);
        }
        x=rnk[x];
        long long d=dist(x,y)+dist(x,z)-dist(y,z);
        if(!vis[x])
        {
            vis[x]=true;
            ans+=d;
        }
        else
        {
            vis[x]=false;
            ans-=d;
        }
        printf("%lld\n",ans);
    }
    return 0;
}
